# apply-worker-govtask-patch.ps1
# worker.js에 GOV_TASK 관련 코드(REQUIRED_DOCUMENTS_REGISTRY, 승인게이트,
# handleGovTaskSubmit 등)와 라우팅 4줄을 삽입한다.
# Base64+BOM 방식 — 이전 웹앱 패치들에서 검증된 안전한 방식 그대로 사용.

$ErrorActionPreference = 'Stop'
try { [Console]::OutputEncoding = [System.Text.Encoding]::UTF8 } catch {}
function _b64d($s) { [System.Text.Encoding]::UTF8.GetString([Convert]::FromBase64String($s)) }
$path = ".\worker.js"
if (-not (Test-Path $path)) { throw "worker.js를 찾을 수 없습니다 — 리포 루트에서 실행하세요." }
$encRead  = [System.Text.Encoding]::UTF8
$encWrite = New-Object System.Text.UTF8Encoding($true)
$content = [System.IO.File]::ReadAllText((Resolve-Path $path), $encRead)
$backupPath = ".\worker.js.bak-$(Get-Date -Format yyyyMMdd-HHmmss)"
Copy-Item $path $backupPath
Write-Host "백업 생성: $backupPath"

$routeOldB64 = ""
$routeNewB64 = ""
$funcOldB64 = "YXN5bmMgZnVuY3Rpb24gaGFuZGxlR292UmVsYXkoYm9keVRleHQsIGVudiwgY29yc0hlYWRlcnMsIG1ldGEgPSBudWxsLCBjdHggPSBudWxsKSB7"
$funcNewB64 = ""

$routeOld = _b64d $routeOldB64
$routeNew = _b64d $routeNewB64
$funcOld = _b64d $funcOldB64
$funcNew = _b64d $funcNewB64

if ($routeOld -notmatch 'gov/relay') { throw 'Base64 디코딩 결과 이상 — routeOld에 gov/relay가 없습니다. PowerShell 버전을 확인하세요.' }

$replacements = @(
  @{ Name = '라우팅 4줄 추가(gov/task/submit 등)'; Old = $routeOld; New = $routeNew },
  @{ Name = 'REQUIRED_DOCUMENTS_REGISTRY 등 GOV_TASK 코드블록 삽입'; Old = $funcOld; New = $funcNew }
)
$applied = 0
foreach ($r in $replacements) {
  if ($content.Contains($r.Old)) {
    $content = $content.Replace($r.Old, $r.New)
    Write-Host "✅ $($r.Name) 치환 완료"
    $applied++
  } else {
    Write-Warning "⚠️ $($r.Name) — 원본과 일치하는 블록을 못 찾았습니다."
  }
}
if ($applied -gt 0) {
  [System.IO.File]::WriteAllText((Resolve-Path $path), $content, $encWrite)
  Write-Host "`nworker.js 저장 완료 (${applied}/2 블록 치환됨)"
} else {
  Write-Host "`n치환된 블록이 없어 파일을 다시 쓰지 않았습니다."
}
Write-Host "`n확인: node --check worker.js  (Node.js 있으면 문법 검증)"
Write-Host "또는: git diff worker.js"
